import React, {useState, useRef} from 'react'
import styled from 'styled-components'
import clothing from './static/clothing.jpg'
import {parseISO, formatDistanceToNow} from 'date-fns'
import heart from './static/heart.png'
import Redheart from './static/Redheart.png'

const CardWrapper = styled.div `
display:inline-block;
margin:10px 10px;
width:200px;
`

const CardImage = styled.div `
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
width:100%;
height:250px;
background-position:center;
background-repeat:no-repeat;
`

const ListingTime = styled.div `
font-size:0.7rem;
color:grey;
margin:5px 0;
`

const Hr = styled.div `
width:100%;
height:1px;
background-color:grey;
`

const ListingTitleWrapper = styled.div `
display:flex;
justify-content:space-between;
margin:5px 0;
`

const ListingTitle = styled.div `
font-size:0.8rem;
font-weight:900;
text-overflow:ellipsis;
overflow:hidden;
white-space: nowrap;
`

const ListingSize = styled.div `
font-size:0.8rem;
font-weight:900;
`
const ListingContent = styled.div `
font-size:0.7rem;
text-overflow:ellipsis;
overflow:hidden;
white-space: nowrap;
`


const ListingFooterWrapper = styled.div `
display:flex;
justify-content:space-between;
margin:5px 0;
`

const ListingPrice = styled.div `
font-size:0.8rem;
font-weight:900;
`

const Heart = styled.div `
font-size:0.7rem;
background-image:url(${heart});
background-position:center;
background-size:cover;
width:15px;
height:15px;
`

const RedHeart = styled.div(Heart) `
background-image:url(${Redheart});
`

export default function ListingCard ({children}) {

	const [isLiked, setIsLiked] = useState(false)

	const onLike = e => {
		setIsLiked(!isLiked)
	}

	return (
		<CardWrapper>
			<CardImage image={children.image_1}></CardImage>
			<ListingTime>{formatDistanceToNow(parseISO(children.createdAt))}</ListingTime>
			<Hr/>
			<ListingTitleWrapper>
				<ListingTitle>{children.itemName}</ListingTitle>
				<ListingSize>{children.size}</ListingSize>
			</ListingTitleWrapper>
			<ListingContent>{children.description}</ListingContent>
			<ListingFooterWrapper>
				<ListingPrice>{children.price}</ListingPrice>
				{isLiked ? <RedHeart onClick={onLike}/> : <Heart onClick={onLike}/>}
			</ListingFooterWrapper>
		</CardWrapper>
	)
}
